 {"id":"asupersync-vswf","title":"Implement comprehensive cancel attribution test suite","description":"## Overview\n\nCreate a comprehensive test suite for cancel attribution, testing the CancelReason type, cause chains, API methods, and real-world debugging scenarios.\n\n## Test Logging Infrastructure\n\n```rust\n/// Initialize test logging for cancel attribution tests\nfn init_cancel_test_logging() {\n    let _ = tracing_subscriber::fmt()\n        .with_max_level(tracing::Level::TRACE)\n        .with_test_writer()\n        .with_span_events(tracing_subscriber::fmt::format::FmtSpan::CLOSE)\n        .try_init();\n}\n\n/// Log cancel chain for debugging\nfn log_cancel_chain(reason: &CancelReason) {\n    tracing::info!(\"Cancel chain:\");\n    for (depth, cause) in reason.chain().enumerate() {\n        tracing::info!(\n            depth = %depth,\n            kind = ?cause.kind,\n            region = ?cause.origin_region,\n            message = cause.message.as_deref(),\n            \"  {} {:?} at {:?}\",\n            \"└─\".repeat(depth + 1),\n            cause.kind,\n            cause.origin_region\n        );\n    }\n}\n```\n\n## Unit Tests\n\n### CancelReason Construction Tests\n```rust\n#[cfg(test)]\nmod cancel_reason_tests {\n    use super::*;\n    \n    #[test]\n    fn basic_construction() {\n        init_cancel_test_logging();\n        \n        let reason = CancelReason::new(CancelKind::User, RegionId(1));\n        \n        assert_eq!(reason.kind, CancelKind::User);\n        assert_eq!(reason.origin_region, RegionId(1));\n        assert!(reason.cause.is_none());\n        \n        tracing::info!(kind = ?reason.kind, \"Basic reason constructed\");\n    }\n    \n    #[test]\n    fn with_message() {\n        init_cancel_test_logging();\n        \n        let reason = CancelReason::new(CancelKind::User, RegionId(1))\n            .with_message(\"User pressed Ctrl+C\");\n        \n        assert_eq!(reason.message, Some(\"User pressed Ctrl+C\".to_string()));\n        \n        tracing::info!(message = ?reason.message, \"Reason with message\");\n    }\n    \n    #[test]\n    fn with_task() {\n        init_cancel_test_logging();\n        \n        let reason = CancelReason::new(CancelKind::Deadline, RegionId(1))\n            .with_task(TaskId(42));\n        \n        assert_eq!(reason.origin_task, Some(TaskId(42)));\n        \n        tracing::info!(task = ?reason.origin_task, \"Reason with task\");\n    }\n    \n    #[test]\n    fn cause_chain_construction() {\n        init_cancel_test_logging();\n        \n        let root = CancelReason::new(CancelKind::Deadline, RegionId(1));\n        let middle = CancelReason::new(CancelKind::ParentCancelled, RegionId(2))\n            .caused_by(root);\n        let leaf = CancelReason::new(CancelKind::ParentCancelled, RegionId(3))\n            .caused_by(middle);\n        \n        // Chain should have 3 elements\n        let chain: Vec<_> = leaf.chain().collect();\n        assert_eq!(chain.len(), 3);\n        \n        // Order: leaf -> middle -> root\n        assert_eq!(chain[0].kind, CancelKind::ParentCancelled);\n        assert_eq!(chain[0].origin_region, RegionId(3));\n        assert_eq!(chain[1].kind, CancelKind::ParentCancelled);\n        assert_eq!(chain[1].origin_region, RegionId(2));\n        assert_eq!(chain[2].kind, CancelKind::Deadline);\n        assert_eq!(chain[2].origin_region, RegionId(1));\n        \n        log_cancel_chain(&leaf);\n    }\n    \n    #[test]\n    fn root_cause() {\n        init_cancel_test_logging();\n        \n        let root = CancelReason::new(CancelKind::Deadline, RegionId(1))\n            .with_message(\"5 second timeout\");\n        let leaf = CancelReason::new(CancelKind::ParentCancelled, RegionId(5))\n            .caused_by(CancelReason::new(CancelKind::ParentCancelled, RegionId(4))\n                .caused_by(CancelReason::new(CancelKind::ParentCancelled, RegionId(3))\n                    .caused_by(CancelReason::new(CancelKind::ParentCancelled, RegionId(2))\n                        .caused_by(root.clone()))));\n        \n        let found_root = leaf.root_cause();\n        assert_eq!(found_root.kind, CancelKind::Deadline);\n        assert_eq!(found_root.message, Some(\"5 second timeout\".to_string()));\n        \n        tracing::info!(\n            root_kind = ?found_root.kind,\n            root_region = ?found_root.origin_region,\n            \"Found root cause through 5-level chain\"\n        );\n    }\n    \n    #[test]\n    fn any_cause_is() {\n        init_cancel_test_logging();\n        \n        let reason = CancelReason::new(CancelKind::ParentCancelled, RegionId(3))\n            .caused_by(CancelReason::new(CancelKind::ParentCancelled, RegionId(2))\n                .caused_by(CancelReason::new(CancelKind::PollQuota, RegionId(1))));\n        \n        // Immediate cause is ParentCancelled\n        assert!(reason.is_kind(CancelKind::ParentCancelled));\n        assert!(!reason.is_kind(CancelKind::PollQuota));\n        \n        // But PollQuota is in the chain\n        assert!(reason.any_cause_is(CancelKind::PollQuota));\n        assert!(!reason.any_cause_is(CancelKind::Deadline));\n        \n        tracing::info!(\"any_cause_is() correctly traverses chain\");\n    }\n}\n```\n\n### CancelKind Tests\n```rust\n#[cfg(test)]\nmod cancel_kind_tests {\n    use super::*;\n    \n    #[test]\n    fn all_variants_constructible() {\n        let kinds = vec![\n            CancelKind::User,\n            CancelKind::Deadline,\n            CancelKind::PollQuota,\n            CancelKind::CostBudget,\n            CancelKind::ParentCancelled,\n            CancelKind::Shutdown,\n            CancelKind::ResourceUnavailable,\n            CancelKind::RaceLost,\n        ];\n        \n        for kind in kinds {\n            let reason = CancelReason::new(kind, RegionId(0));\n            assert_eq!(reason.kind, kind);\n            tracing::debug!(kind = ?kind, \"CancelKind variant works\");\n        }\n    }\n    \n    #[test]\n    fn kinds_are_eq_and_hash() {\n        use std::collections::HashSet;\n        \n        let mut set = HashSet::new();\n        set.insert(CancelKind::User);\n        set.insert(CancelKind::Deadline);\n        \n        assert!(set.contains(&CancelKind::User));\n        assert!(!set.contains(&CancelKind::Shutdown));\n    }\n}\n```\n\n## Integration Tests\n\n### Cx API Tests\n```rust\n#[cfg(test)]\nmod cx_cancel_api_tests {\n    use super::*;\n    \n    #[test]\n    fn cancel_with_stores_reason() {\n        init_cancel_test_logging();\n        \n        let lab = LabRuntimeBuilder::new().rng_seed(42).build();\n        \n        lab.run_with_cx(|cx| async move {\n            tracing::debug!(\"Cancelling with detailed reason\");\n            cx.cancel_with(CancelKind::User, \"Test cancellation\");\n            \n            let reason = cx.cancel_reason().expect(\"Should have reason\");\n            \n            assert_eq!(reason.kind, CancelKind::User);\n            assert_eq!(reason.message, Some(\"Test cancellation\".to_string()));\n            assert_eq!(reason.origin_region, cx.region_id());\n            \n            tracing::info!(\n                kind = ?reason.kind,\n                message = ?reason.message,\n                \"Cancel reason stored correctly\"\n            );\n        });\n    }\n    \n    #[test]\n    fn cancel_chain_api() {\n        init_cancel_test_logging();\n        \n        let lab = LabRuntimeBuilder::new().rng_seed(42).build();\n        \n        lab.run_with_cx(|cx| async move {\n            let result = cx.region(|child_cx| async move {\n                child_cx.region(|grandchild_cx| async move {\n                    // Wait to be cancelled\n                    grandchild_cx.cancellation().await;\n                    \n                    // Check the chain\n                    let chain: Vec<_> = grandchild_cx.cancel_chain().collect();\n                    \n                    tracing::info!(chain_len = %chain.len(), \"Cancel chain captured\");\n                    \n                    for (i, cause) in chain.iter().enumerate() {\n                        tracing::debug!(\n                            depth = %i,\n                            kind = ?cause.kind,\n                            region = ?cause.origin_region,\n                            \"Chain element\"\n                        );\n                    }\n                    \n                    // Should have: grandchild (ParentCancelled) -> child (ParentCancelled) -> root (User)\n                    assert!(chain.len() >= 2);\n                    assert!(grandchild_cx.any_cause_is(CancelKind::User));\n                }).await;\n                \n                child_cx.cancellation().await;\n            }).await;\n            \n            // Cancel the parent\n            tracing::debug!(\"Triggering cancellation from root\");\n            cx.cancel_with(CancelKind::User, \"Triggered from test\");\n        });\n    }\n    \n    #[test]\n    fn root_cancel_cause_api() {\n        init_cancel_test_logging();\n        \n        let lab = LabRuntimeBuilder::new().rng_seed(42).build();\n        \n        let seen_root = Arc::new(Mutex::new(None));\n        let seen_root2 = seen_root.clone();\n        \n        lab.run_with_cx(|cx| async move {\n            cx.with_budget(Budget::deadline(Duration::from_millis(10)), async {\n                cx.region(|child| async move {\n                    child.region(|grandchild| async move {\n                        // Wait to be cancelled by deadline\n                        grandchild.cancellation().await;\n                        \n                        if let Some(root) = grandchild.root_cancel_cause() {\n                            *seen_root2.lock().unwrap() = Some(root.kind);\n                            \n                            tracing::info!(\n                                root_kind = ?root.kind,\n                                \"Found root cause through nested regions\"\n                            );\n                        }\n                    }).await;\n                }).await;\n            }).await;\n        });\n        \n        // Root cause should be Deadline, not ParentCancelled\n        assert_eq!(*seen_root.lock().unwrap(), Some(CancelKind::Deadline));\n    }\n    \n    #[test]\n    fn cancelled_by_api() {\n        init_cancel_test_logging();\n        \n        let lab = LabRuntimeBuilder::new().rng_seed(42).build();\n        \n        lab.run_with_cx(|cx| async move {\n            cx.cancel_with(CancelKind::Shutdown, \"Graceful shutdown\");\n            \n            assert!(cx.cancelled_by(CancelKind::Shutdown));\n            assert!(!cx.cancelled_by(CancelKind::Deadline));\n            \n            tracing::info!(\"cancelled_by() API works correctly\");\n        });\n    }\n}\n```\n\n## E2E Tests\n\n### Real-World Debugging Scenario\n```rust\n#[test]\nfn e2e_debugging_workflow() {\n    init_cancel_test_logging();\n    \n    tracing::info!(\"═══════════════════════════════════════════\");\n    tracing::info!(\"E2E: Cancel Attribution Debugging Workflow\");\n    tracing::info!(\"═══════════════════════════════════════════\");\n    \n    let lab = LabRuntimeBuilder::new()\n        .rng_seed(42)\n        .build();\n    \n    // Simulate a service with nested timeouts\n    lab.run_with_cx(|cx| async move {\n        // Service-level timeout: 5 seconds\n        let result = cx.with_budget(\n            Budget::deadline(Duration::from_secs(5)),\n            async {\n                // Handler timeout: 1 second\n                cx.with_budget(\n                    Budget::deadline(Duration::from_secs(1)),\n                    async {\n                        // Database timeout: 100ms\n                        cx.with_budget(\n                            Budget::deadline(Duration::from_millis(100)),\n                            async {\n                                // Slow query that takes too long\n                                sleep(Duration::from_millis(200)).await;\n                                42\n                            }\n                        ).await\n                    }\n                ).await\n            }\n        ).await;\n        \n        // Debugging: What happened?\n        if let Outcome::Cancelled(_) = &result {\n            tracing::info!(\"Request was cancelled - investigating...\");\n            \n            if let Some(reason) = cx.cancel_reason() {\n                // Print the full chain\n                tracing::info!(\"Cancel attribution chain:\");\n                for (depth, cause) in reason.chain().enumerate() {\n                    let indent = \"  \".repeat(depth);\n                    tracing::info!(\n                        \"{}{:?} at region {:?} ({:?})\",\n                        indent,\n                        cause.kind,\n                        cause.origin_region,\n                        cause.message.as_deref().unwrap_or(\"no message\")\n                    );\n                }\n                \n                // Actionable insight\n                let root = reason.root_cause();\n                if root.kind == CancelKind::Deadline {\n                    tracing::warn!(\n                        \"Root cause: Deadline at region {:?}\",\n                        root.origin_region\n                    );\n                    tracing::warn!(\"Consider: Increase timeout or optimize query\");\n                }\n            }\n        }\n    });\n    \n    tracing::info!(\"E2E debugging workflow completed\");\n}\n\n#[test]\nfn e2e_metrics_collection() {\n    init_cancel_test_logging();\n    \n    tracing::info!(\"═══════════════════════════════════════════\");\n    tracing::info!(\"E2E: Cancel Attribution Metrics Collection\");\n    tracing::info!(\"═══════════════════════════════════════════\");\n    \n    // Simulate collecting metrics from cancellation reasons\n    struct CancelMetrics {\n        by_kind: HashMap<CancelKind, usize>,\n        total_chain_depth: usize,\n        count: usize,\n    }\n    \n    let metrics = Arc::new(Mutex::new(CancelMetrics {\n        by_kind: HashMap::new(),\n        total_chain_depth: 0,\n        count: 0,\n    }));\n    \n    let lab = LabRuntimeBuilder::new().rng_seed(42).build();\n    \n    // Run several requests with various cancellation scenarios\n    for i in 0..10 {\n        let metrics = metrics.clone();\n        \n        lab.run_with_cx(|cx| async move {\n            let budget = match i % 3 {\n                0 => Budget::deadline(Duration::from_millis(10)),\n                1 => Budget::poll_quota(5),\n                _ => Budget::cost(100),\n            };\n            \n            let result = cx.with_budget(budget, async {\n                // Simulate work that might exceed budget\n                for _ in 0..20 {\n                    yield_now().await;\n                }\n            }).await;\n            \n            if let Outcome::Cancelled(_) = result {\n                if let Some(reason) = cx.cancel_reason() {\n                    let mut m = metrics.lock().unwrap();\n                    \n                    // Count by kind\n                    *m.by_kind.entry(reason.kind).or_insert(0) += 1;\n                    \n                    // Track chain depth\n                    let depth = reason.chain().count();\n                    m.total_chain_depth += depth;\n                    m.count += 1;\n                }\n            }\n        });\n    }\n    \n    let m = metrics.lock().unwrap();\n    tracing::info!(\"Cancellation metrics collected:\");\n    for (kind, count) in &m.by_kind {\n        tracing::info!(\"  {:?}: {}\", kind, count);\n    }\n    if m.count > 0 {\n        tracing::info!(\n            \"  Average chain depth: {:.1}\",\n            m.total_chain_depth as f64 / m.count as f64\n        );\n    }\n}\n```\n\n## Test Execution Script\n\nCreate `scripts/test_cancel_attribution.sh`:\n\n```bash\n#!/bin/bash\nset -euo pipefail\n\necho \"═══════════════════════════════════════════════════════════════\"\necho \"          Cancel Attribution Test Suite                        \"\necho \"═══════════════════════════════════════════════════════════════\"\n\nexport RUST_LOG=trace\nexport RUST_BACKTRACE=1\n\necho \"\"\necho \"▶ Running CancelReason unit tests...\"\ncargo test cancel_reason_tests --lib -- --nocapture 2>&1 | tee /tmp/cancel_reason_tests.log\n\necho \"\"\necho \"▶ Running CancelKind unit tests...\"\ncargo test cancel_kind_tests --lib -- --nocapture 2>&1 | tee /tmp/cancel_kind_tests.log\n\necho \"\"\necho \"▶ Running Cx API tests...\"\ncargo test cx_cancel_api_tests --lib -- --nocapture 2>&1 | tee /tmp/cx_cancel_api_tests.log\n\necho \"\"\necho \"▶ Running E2E tests...\"\ncargo test e2e_debugging_workflow -- --nocapture 2>&1 | tee /tmp/cancel_e2e_tests.log\ncargo test e2e_metrics_collection -- --nocapture 2>&1 | tee -a /tmp/cancel_e2e_tests.log\n\necho \"\"\necho \"═══════════════════════════════════════════════════════════════\"\necho \"                    TEST SUMMARY                                \"\necho \"═══════════════════════════════════════════════════════════════\"\n\nPASSED=$(grep -c \"test .* ok\" /tmp/cancel_*.log || true)\nFAILED=$(grep -c \"test .* FAILED\" /tmp/cancel_*.log || true)\n\necho \"Tests passed: $PASSED\"\necho \"Tests failed: $FAILED\"\n\nif [ \"$FAILED\" -gt 0 ]; then\n    echo \"\"\n    echo \"FAILED TESTS:\"\n    grep \"FAILED\" /tmp/cancel_*.log || true\n    exit 1\nfi\n\necho \"\"\necho \"✓ All cancel attribution tests passed!\"\n```\n\n## Acceptance Criteria\n\n- [ ] CancelReason construction tests (all fields)\n- [ ] Cause chain construction and traversal tests\n- [ ] root_cause() tested with various chain depths\n- [ ] any_cause_is() tested with various chain contents\n- [ ] Cx API tests for all cancel attribution methods\n- [ ] E2E debugging workflow demonstrating real-world usage\n- [ ] E2E metrics collection demonstrating observability\n- [ ] All tests produce TRACE-level logs\n- [ ] Test execution script for CI/CD","status":"closed","priority":2,"issue_type":"task","assignee":"CalmHawk","created_at":"2026-01-18T19:17:34.070442780Z","created_by":"Dicklesworthstone","updated_at":"2026-01-30T02:41:22.282796861Z","closed_at":"2026-01-30T02:41:22.282697847Z","close_reason":"Completed: cancel attribution suite present; cargo test --test cancel_attribution passes (2026-01-30)","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"asupersync-vswf","depends_on_id":"asupersync-776m","type":"blocks","created_at":"2026-02-13T18:30:17Z","created_by":"import","metadata":"{}","thread_id":""},{"issue_id":"asupersync-vswf","depends_on_id":"asupersync-9uy4","type":"blocks","created_at":"2026-02-13T18:30:17Z","created_by":"import","metadata":"{}","thread_id":""}]}
